import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F17_籌碼分佈與法人動態分析.md"}'),i={name:"審計報告庫/財務審計/6290_良維/20260424/F17_籌碼分佈與法人動態分析.md"};function o(n,t,d,s,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="f17-籌碼分佈與法人動態分析-投資研究員審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 投資研究員審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-投資研究員審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2026年4月最新公開數據，良維法人籌碼呈現「外資偏多調節、自營商獲利出場、大戶比例高位收斂」的結構。2026年Q1外資累計淨買超822萬張（註：股數），但4月以來外資淨賣超296萬張，顯示外資在300元歷史高檔區進行獲利了結。千張大戶佔比從3月初的47.4%降至37.5%，降幅近10%。綜合評級為B（持平）：籌碼正從高度集中轉向鬆動，高位派發壓力浮現。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：B（持平 - 高位派發警訊）</strong></p><p>關鍵數據基石：</p><ul><li><strong>2026 Q1法人合計</strong>：淨買超718.8萬張（外資+822萬、自營商避險+24萬、投信-25萬、自營商-103萬）</li><li><strong>2026年4月至今</strong>：法人合計淨賣超733萬張（外資-296萬、自營避險-47萬、自營商-404萬、投信+14萬）</li><li><strong>千張大戶佔比</strong>：從47.4%（3/6）降至37.5%（4/17），降幅995bps</li><li><strong>400張以上合計</strong>：從57.5%降至50.5%</li><li><strong>散戶人數</strong>：3月39,541人增至4月45,831人（+15.9%）</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、法人買賣超趨勢分析</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">機構</th><th style="text-align:right;">Q1 2026淨買超(張)</th><th style="text-align:right;">4月至今淨買超(張)</th><th style="text-align:left;">動向判讀</th></tr></thead><tbody><tr><td style="text-align:left;">外資</td><td style="text-align:right;">+8,223,095</td><td style="text-align:right;">-2,962,623</td><td style="text-align:left;">Q1偏多→4月獲利出場</td></tr><tr><td style="text-align:left;">投信</td><td style="text-align:right;">-248,782</td><td style="text-align:right;">+137,290</td><td style="text-align:left;">中性偏低，非主動買盤</td></tr><tr><td style="text-align:left;">自營商(自行)</td><td style="text-align:right;">-1,029,374</td><td style="text-align:right;">-4,037,505</td><td style="text-align:left;">持續減碼</td></tr><tr><td style="text-align:left;">自營商(避險)</td><td style="text-align:right;">+243,102</td><td style="text-align:right;">-466,876</td><td style="text-align:left;">中性</td></tr><tr><td style="text-align:left;"><strong>合計</strong></td><td style="text-align:right;"><strong>+7,188,041</strong></td><td style="text-align:right;"><strong>-7,329,714</strong></td><td style="text-align:left;">多空逆轉</td></tr></tbody></table><p>關鍵觀察：3月股價在198-227元區間時，外資積極買超。4月股價突破230元後，外資轉為淨賣超，且在股價觸及306.5元時賣壓顯著加大。這是典型的高位獲利了結特徵。</p><p><strong>二、大戶籌碼變動（鎖碼/派發判讀）</strong></p><p>大戶（400張以上）持股比從3月初57.5%降至4月中50.5%，對應股價從約200元漲至306.5元（+53%）。股價上漲但大戶減持——這是「高位派發」的標準訊號。</p><p>然而，並非全面性逃命：</p><ul><li>千張以上大戶絕對張數：3/27有68,209張，4/17仍有63,602張，僅減少4,607張（-6.8%）</li><li>400-1000張大戶反而從3/27的18,413張增至4/17的21,974張（+19.3%），顯示中實戶仍在收集</li></ul><p><strong>三、散戶化警示</strong></p><p>總股東人數從3月初38,575人激增至4月中45,831人，一個半月增加7,256人（+18.8%）。新增股東集中在1-5張的小散戶，顯示股價飆漲吸引散戶跟風追價。當散戶持股集中度上升而大戶下降，通常是股價接近短期頭部的徵兆。</p><h2 id="💡-專家評級" tabindex="-1">💡 專家評級 <a class="header-anchor" href="#💡-專家評級" aria-label="Permalink to &quot;💡 專家評級&quot;">​</a></h2><p><strong>風險評估</strong>：</p><ol><li><strong>外資獲利出場明確</strong>：4月以來外資累計淨賣超約296萬張（值約7-9億元），動能由正向轉為負向。</li><li><strong>大戶高位減持</strong>：千張大戶佔比從47%降至37%，雖然絕對張數減幅不大，但趨勢方向明確。</li><li><strong>散戶追價風險</strong>：股東人數暴增19%，散戶化程度加速，若股價反轉將面臨套牢風險。</li><li><strong>投信未參與拉抬</strong>：投信持股極低、無明顯買超，代表本土法人尚未認同此波漲勢。</li></ol><p><strong>投信持股分析</strong>：投信買賣超極低（Q1淨賣超24.9萬張，4月淨買超13.7萬張），投信持股比例遠低於15%，無「結帳壓力」。但同時也意味本波漲勢缺乏法人機構的實質基本面背書。</p><p><strong>華爾街空頭視角</strong>：當「散戶人數創高、大戶佔比創低、外資由買轉賣」三者同時出現，是高位派發的經典組合。建議密切關注：若未來1-2週千張大戶持續降至35%以下且外資單週賣超超過500萬張，應視為強烈撤退信號。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>institutional 6290 2026-01-01 2026-04-24 --df</code> (科目：三大法人每日買賣超)</li><li><code>數據採集器查詢</code>: <code>backer_holding 6290 2026-03-01 2026-04-24 --df</code> (科目：股權分散表各級距)</li><li><code>自訂計算</code>: 法人合計淨買超 = 各法人 (Buy - Sell) 加總</li><li><code>自訂計算</code>: 大戶佔比變動 = 各期 HoldingSharesLevel &quot;more than 1,000,001&quot; percent 差額</li><li><code>數據採集器查詢</code>: <code>holding 6290 2026-01-01 2026-04-24 --df</code> (科目：外資持股比例趨勢)</li></ul>',26)])])}const _=e(i,[["render",o]]);export{p as __pageData,_ as default};
